class Circle:
    def __init__(self, radius):
        self.radius = radius

    def area(self):
        return 3.14 * self.radius * self.radius

    def __str__(self):
        return "Circle with radius " + str(self.radius)

    def __repr__(self):
        return "Circle(" + str(self.radius) + ")"

    def __eq__(self, other):
        return self.radius == other.radius

c1 = Circle(5)
c2 = Circle(5)
c3 = Circle(9)

print(c1)              # uses __str__
print(c1.area())
print(c1 == c2)        # uses __eq__ -> True
print(c1 == c3)        # uses __eq__ -> False
print([c1, c3])        # lists use __repr__

class Team:
    def __init__(self, name, players):
        self.name = name
        self.players = players

    def __str__(self):
        return "Team " + self.name + " with " + str(len(self.players)) + " players"

    def __len__(self):
        return len(self.players)

lions = Team("Lions", ["Sam", "Ava", "Leo"])

print(lions)          # uses __str__
print(len(lions))     # uses __len__ -> 3

