    def __init__(self, name):
        self.name = name

# class Square(Shape): use super().__init__("Square"), store side, add area() and __str__

# class Rectangle(Shape): use super().__init__("Rectangle"), store width/height, add area() and __str__

# create a Square and a Rectangle, print each one, print each area

challenge.solution:
class Shape:
    def __init__(self, name):
        self.name = name

class Square(Shape):
    def __init__(self, side):
        super().__init__("Square")
        self.side = side

    def area(self):
        return self.side * self.side

    def __str__(self):
        return self.name + " with area " + str(self.area())

class Rectangle(Shape):
    def __init__(self, width, height):
        super().__init__("Rectangle")
        self.width = width
        self.height = height

    def area(self):
        return self.width * self.height

    def __str__(self):
        return self.name + " with area " + str(self.area())

sq = Square(4)
rect = Rectangle(3, 5)
print(sq)
print(rect)
print(sq.area())
print(rect.area())
